use async_trait::async_trait;

use crate::{
    Result,
    types::{Contact, ContactChannel, Interaction, Matter},
};

/// Persistence trait for CRM data.
///
/// Provides CRUD operations for [`Contact`], [`Matter`], [`Interaction`], and
/// [`ContactChannel`] records. Implementations include [`SqliteCrmStore`] for
/// production use and [`MemoryCrmStore`] for testing.
#[async_trait]
pub trait CrmStore: Send + Sync {
    // ── Contacts ──────────────────────────────────────────────────────────────

    /// Return all contacts ordered by most-recently-updated first.
    async fn list(&self) -> Result<Vec<Contact>>;

    /// Return a single contact by ID, or `None` if not found.
    async fn get(&self, id: &str) -> Result<Option<Contact>>;

    /// Look up a contact by source channel and external ID.
    async fn get_by_external(&self, source: &str, external_id: &str) -> Result<Option<Contact>>;

    /// Insert or update a contact (upsert by ID).
    async fn upsert(&self, contact: Contact) -> Result<()>;

    /// Delete a contact by ID. Returns `Ok(())` if not found (idempotent).
    async fn delete(&self, id: &str) -> Result<()>;

    // ── Contact channels ──────────────────────────────────────────────────────

    /// Return all channel identities for a contact.
    async fn list_channels_for_contact(&self, contact_id: &str) -> Result<Vec<ContactChannel>>;

    /// Look up a channel identity by channel type and channel-native ID.
    async fn get_channel_by_external(
        &self,
        channel_type: &str,
        channel_id: &str,
    ) -> Result<Option<ContactChannel>>;

    /// Insert or update a channel identity (upsert by ID).
    async fn upsert_channel(&self, channel: ContactChannel) -> Result<()>;

    /// Delete a channel identity by ID. Returns `Ok(())` if not found (idempotent).
    async fn delete_channel(&self, id: &str) -> Result<()>;

    // ── Matters ───────────────────────────────────────────────────────────────

    /// Return all matters ordered by most-recently-updated first.
    async fn list_matters(&self) -> Result<Vec<Matter>>;

    /// Return all matters for a contact, ordered by most-recently-updated first.
    async fn list_matters_by_contact(&self, contact_id: &str) -> Result<Vec<Matter>>;

    /// Return a single matter by ID, or `None` if not found.
    async fn get_matter(&self, id: &str) -> Result<Option<Matter>>;

    /// Insert or update a matter (upsert by ID).
    async fn upsert_matter(&self, matter: Matter) -> Result<()>;

    /// Delete a matter by ID. Returns `Ok(())` if not found (idempotent).
    async fn delete_matter(&self, id: &str) -> Result<()>;

    // ── Interactions ──────────────────────────────────────────────────────────

    /// Return all interactions for a contact, ordered by most-recently-updated first.
    async fn list_interactions_by_contact(&self, contact_id: &str) -> Result<Vec<Interaction>>;

    /// Return all interactions for a matter, ordered by most-recently-updated first.
    async fn list_interactions_by_matter(&self, matter_id: &str) -> Result<Vec<Interaction>>;

    /// Return a single interaction by ID, or `None` if not found.
    async fn get_interaction(&self, id: &str) -> Result<Option<Interaction>>;

    /// Insert or update an interaction (upsert by ID).
    async fn upsert_interaction(&self, interaction: Interaction) -> Result<()>;

    /// Delete an interaction by ID. Returns `Ok(())` if not found (idempotent).
    async fn delete_interaction(&self, id: &str) -> Result<()>;
}

pub use crate::{store_memory::MemoryCrmStore, store_sqlite::SqliteCrmStore};

use {
    async_trait::async_trait,
    moltis_channels::{
        Error as ChannelError, Result as ChannelResult,
        message_log::{MessageLog, MessageLogEntry, SenderSummary},
    },
    sqlx::SqlitePool,
};

fn channel_db_error(context: &'static str, source: sqlx::Error) -> ChannelError {
    ChannelError::external(context, source)
}

/// SQLite-backed message log.
pub struct SqliteMessageLog {
    pool: SqlitePool,
}

impl SqliteMessageLog {
    pub fn new(pool: SqlitePool) -> Self {
        Self { pool }
    }

    /// Initialize the message_log table schema.
    ///
    /// **Deprecated**: Schema is now managed by sqlx migrations.
    /// This method is retained for tests that use in-memory databases.
    #[doc(hidden)]
    pub async fn init(pool: &SqlitePool) -> ChannelResult<()> {
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS message_log (
                id             INTEGER PRIMARY KEY AUTOINCREMENT,
                account_id     TEXT    NOT NULL,
                channel_type   TEXT    NOT NULL,
                peer_id        TEXT    NOT NULL,
                username       TEXT,
                sender_name    TEXT,
                chat_id        TEXT    NOT NULL,
                chat_type      TEXT    NOT NULL,
                body           TEXT    NOT NULL,
                access_granted INTEGER NOT NULL DEFAULT 0,
                created_at     INTEGER NOT NULL
            )",
        )
        .execute(pool)
        .await
        .map_err(|e| channel_db_error("init message_log table", e))?;

        sqlx::query(
            "CREATE INDEX IF NOT EXISTS idx_message_log_channel_account_created
             ON message_log (channel_type, account_id, created_at DESC)",
        )
        .execute(pool)
        .await
        .map_err(|e| channel_db_error("init message_log indexes", e))?;

        Ok(())
    }
}

#[async_trait]
impl MessageLog for SqliteMessageLog {
    async fn log(&self, entry: MessageLogEntry) -> ChannelResult<()> {
        sqlx::query(
            "INSERT INTO message_log
             (account_id, channel_type, peer_id, username, sender_name,
              chat_id, chat_type, body, access_granted, created_at)
             VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
        )
        .bind(&entry.account_id)
        .bind(&entry.channel_type)
        .bind(&entry.peer_id)
        .bind(&entry.username)
        .bind(&entry.sender_name)
        .bind(&entry.chat_id)
        .bind(&entry.chat_type)
        .bind(&entry.body)
        .bind(entry.access_granted)
        .bind(entry.created_at)
        .execute(&self.pool)
        .await
        .map_err(|e| channel_db_error("log channel message", e))?;
        Ok(())
    }

    async fn list_by_account(
        &self,
        channel_type: &str,
        account_id: &str,
        limit: u32,
    ) -> ChannelResult<Vec<MessageLogEntry>> {
        let rows = sqlx::query_as::<
            _,
            (
                i64,
                String,
                String,
                String,
                Option<String>,
                Option<String>,
                String,
                String,
                String,
                bool,
                i64,
            ),
        >(
            "SELECT id, account_id, channel_type, peer_id, username, sender_name,
                    chat_id, chat_type, body, access_granted, created_at
             FROM message_log
             WHERE channel_type = ? AND account_id = ?
             ORDER BY created_at DESC
             LIMIT ?",
        )
        .bind(channel_type)
        .bind(account_id)
        .bind(limit)
        .fetch_all(&self.pool)
        .await
        .map_err(|e| channel_db_error("list channel messages", e))?;

        Ok(rows
            .into_iter()
            .map(|r| MessageLogEntry {
                id: r.0,
                account_id: r.1,
                channel_type: r.2,
                peer_id: r.3,
                username: r.4,
                sender_name: r.5,
                chat_id: r.6,
                chat_type: r.7,
                body: r.8,
                access_granted: r.9,
                created_at: r.10,
            })
            .collect())
    }

    async fn unique_senders(
        &self,
        channel_type: &str,
        account_id: &str,
    ) -> ChannelResult<Vec<SenderSummary>> {
        let rows = sqlx::query_as::<_, (String, Option<String>, Option<String>, i64, i64, bool)>(
            "SELECT peer_id, username, sender_name,
                    COUNT(*) as message_count,
                    MAX(created_at) as last_seen,
                    MAX(CASE WHEN access_granted THEN 1 ELSE 0 END) as last_access_granted
             FROM message_log
             WHERE channel_type = ? AND account_id = ?
             GROUP BY peer_id
             ORDER BY last_seen DESC",
        )
        .bind(channel_type)
        .bind(account_id)
        .fetch_all(&self.pool)
        .await
        .map_err(|e| channel_db_error("list channel senders", e))?;

        Ok(rows
            .into_iter()
            .map(|r| SenderSummary {
                peer_id: r.0,
                username: r.1,
                sender_name: r.2,
                message_count: r.3,
                last_seen: r.4,
                last_access_granted: r.5,
            })
            .collect())
    }
}

#[allow(clippy::unwrap_used, clippy::expect_used)]
#[cfg(test)]
mod tests {
    use super::*;

    async fn test_pool() -> SqlitePool {
        let pool = SqlitePool::connect("sqlite::memory:").await.unwrap();
        SqliteMessageLog::init(&pool).await.unwrap();
        pool
    }

    fn sample_entry(account_id: &str, peer_id: &str, granted: bool) -> MessageLogEntry {
        MessageLogEntry {
            id: 0,
            account_id: account_id.into(),
            channel_type: "telegram".into(),
            peer_id: peer_id.into(),
            username: Some("testuser".into()),
            sender_name: Some("Test User".into()),
            chat_id: "12345".into(),
            chat_type: "dm".into(),
            body: "hello".into(),
            access_granted: granted,
            created_at: 1700000000,
        }
    }

    #[tokio::test]
    async fn log_and_list() {
        let pool = test_pool().await;
        let store = SqliteMessageLog::new(pool);

        store
            .log(sample_entry("bot1", "user1", true))
            .await
            .unwrap();
        store
            .log(sample_entry("bot1", "user2", false))
            .await
            .unwrap();
        store
            .log(sample_entry("bot2", "user3", true))
            .await
            .unwrap();

        let entries = store.list_by_account("telegram", "bot1", 10).await.unwrap();
        assert_eq!(entries.len(), 2);

        let entries = store.list_by_account("telegram", "bot2", 10).await.unwrap();
        assert_eq!(entries.len(), 1);
    }

    #[tokio::test]
    async fn list_respects_limit() {
        let pool = test_pool().await;
        let store = SqliteMessageLog::new(pool);

        for i in 0..5 {
            let mut e = sample_entry("bot1", "user1", true);
            e.created_at = 1700000000 + i;
            store.log(e).await.unwrap();
        }

        let entries = store.list_by_account("telegram", "bot1", 3).await.unwrap();
        assert_eq!(entries.len(), 3);
        // Most recent first
        assert!(entries[0].created_at > entries[1].created_at);
    }

    #[tokio::test]
    async fn unique_senders_groups() {
        let pool = test_pool().await;
        let store = SqliteMessageLog::new(pool);

        store
            .log(sample_entry("bot1", "user1", true))
            .await
            .unwrap();
        store
            .log(sample_entry("bot1", "user1", false))
            .await
            .unwrap();
        store
            .log(sample_entry("bot1", "user2", true))
            .await
            .unwrap();

        let senders = store.unique_senders("telegram", "bot1").await.unwrap();
        assert_eq!(senders.len(), 2);
        let user1 = senders.iter().find(|s| s.peer_id == "user1").unwrap();
        assert_eq!(user1.message_count, 2);
    }
}

