        .bind(&channel.channel_type)
        .bind(&channel.channel_id)
        .bind(&channel.display_name)
        .bind(channel.verified as i64)
        .bind(channel.created_at as i64)
        .bind(channel.updated_at as i64)
        .execute(&self.pool)
