        let report = engine.run_once().await;
        assert_eq!(report.crm_interactions_deleted, 1, "ancient record should be deleted");

        assert!(crm.get_interaction(&old.id).await.unwrap().is_none(), "old gone");
        assert!(crm.get_interaction(&recent.id).await.unwrap().is_some(), "recent kept");
    }
