            info!(
                openclaw_home_env = %env_var_or_unset("OPENCLAW_HOME"),
                openclaw_profile_env = %env_var_or_unset("OPENCLAW_PROFILE"),
                "startup OpenClaw installation not detected (checked OPENCLAW_HOME and ~/.openclaw)"
