            Some(outbound.clone() as Arc<dyn moltis_channels::ChannelOutbound>),
            &req,
            "Daily digest ready",
        )
        .await;

        let delivered = outbound.delivered.lock().await.clone();
        assert_eq!(delivered, vec![DeliveredMessage {
